import { useTheme } from 'next-themes';
import type { CSSProperties } from 'react';
import { Toaster, ToasterProps } from 'sonner';

const toasterStyle = {
  '--border-radius': '0px',
  '--normal-bg': 'var(--background)',
  '--normal-border': 'var(--border)',
  '--normal-text': 'var(--foreground)',
  '--toast-close-button-end': '0',
  '--toast-close-button-start': 'unset',
  '--toast-close-button-transform': 'none',
} as CSSProperties;

const toastStyle = {
  borderRadius: 0,
  boxShadow: 'none',
  fontFamily: 'var(--font-mono)',
} satisfies CSSProperties;

const toastButtonStyle = {
  borderRadius: 0,
} satisfies CSSProperties;

export const Sonner = ({ ...props }: ToasterProps) => {
  const { resolvedTheme, theme } = useTheme();
  const sonnerTheme = (resolvedTheme ?? theme) === 'dark' ? 'dark' : 'light';

  return (
    <Toaster
      theme={sonnerTheme}
      className="toaster group mt-safe-top font-mono"
      closeButton
      position="top-center"
      style={toasterStyle}
      offset={{
        top: 'calc(16px + env(safe-area-inset-top))',
        bottom: 'calc(16px + env(safe-area-inset-bottom))',
        left: 'calc(16px + env(safe-area-inset-left))',
        right: 'calc(16px + env(safe-area-inset-right))',
      }}
      mobileOffset={{
        top: 'calc(8px + env(safe-area-inset-top))',
        bottom: 'calc(8px + env(safe-area-inset-bottom))',
        left: 'calc(8px + env(safe-area-inset-left))',
        right: 'calc(8px + env(safe-area-inset-right))',
      }}
      toastOptions={{
        actionButtonStyle: toastButtonStyle,
        cancelButtonStyle: toastButtonStyle,
        closeButtonAriaLabel: 'Dismiss notification',
        style: toastStyle,
        classNames: {
          toast:
            'group toast group-[.toaster]:rounded-none group-[.toaster]:border-border group-[.toaster]:bg-background group-[.toaster]:text-foreground group-[.toaster]:shadow-none',
          title: 'group-[.toast]:text-xs group-[.toast]:leading-5',
          description:
            'group-[.toast]:text-xs group-[.toast]:leading-5 group-[.toast]:text-muted-foreground',
          icon: 'group-[.toast]:text-foreground',
          actionButton:
            'group-[.toast]:rounded-none group-[.toast]:bg-primary group-[.toast]:font-medium group-[.toast]:text-primary-foreground',
          cancelButton:
            'group-[.toast]:rounded-none group-[.toast]:bg-muted group-[.toast]:font-medium group-[.toast]:text-muted-foreground',
          closeButton:
            'group-[.toast]:!rounded-none group-[.toast]:!border-border group-[.toast]:!bg-background group-[.toast]:!text-muted-foreground group-[.toast]:hover:!bg-accent group-[.toast]:hover:!text-foreground',
        },
      }}
      {...props}
    />
  );
};

